class Queue:
    def __init__(self):
        self.items = []

    def enqueue(self, item):
        """Kuyruğa eleman ekler."""
        self.items.append(item)

    def dequeue(self):
        """Kuyruğun başından elemanı çıkarır ve döndürür."""
        if not self.items:
            raise IndexError("Kuyruk boş, dequeue yapılamaz.")
        return self.items.pop(0)

    def is_empty(self):
        """Kuyruğun boş olup olmadığını kontrol eder."""
        return len(self.items) == 0

    def size(self):
        """Kuyruktaki eleman sayısını döndürür."""
        return len(self.items)

    def peek(self):
        """Kuyruğun başındaki elemanı döndürür, kuyruktan çıkarmaz."""
        if not self.items:
            raise IndexError("Kuyruk boş, peek yapılamaz.")
        return self.items[0]

    def __str__(self):
        """Kuyruğun string temsilini döndürür."""
        return f"Queue({self.items})"

    def __repr__(self):
        """Kuyruğun temsilini döndürür."""
        return f"Queue({self.items})"
